const items = $input.all();

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const seen = new Set();
const validRows = [];
const skippedResults = [];

for (const item of items) {
  const data = item.json;
  const jobNumber = (data.jobNumber || '').toString().trim();
  const siteAddress = (data.siteAddress || '').toString().trim();
  const email = (data.email || '').toString().trim();
  const siteContactFirst = (data.siteContactFirst || '').toString().trim();
  const siteContactLast = (data.siteContactLast || '').toString().trim();
  const contactName = `${siteContactFirst} ${siteContactLast}`.trim();

  const blockingReasons = [];
  if (!jobNumber) blockingReasons.push('Missing job number');
  if (!siteAddress) blockingReasons.push('Missing site address');
  if (!email) blockingReasons.push('Missing email');
  else if (!emailRegex.test(email)) blockingReasons.push('Email format looks invalid');

  if (blockingReasons.length > 0) {
    skippedResults.push({ jobNumber: jobNumber || '(missing)', siteAddress: siteAddress || '(missing)', contact: contactName, email, status: 'invalid', detail: blockingReasons.join('; ') });
    continue;
  }
  if (seen.has(jobNumber)) {
    skippedResults.push({ jobNumber, siteAddress, contact: contactName, email, status: 'duplicate_in_file', detail: 'Same job number appears more than once in the uploaded file' });
    continue;
  }
  seen.add(jobNumber);
  validRows.push({ json: { jobNumber, siteAddress, email, siteContactFirst, siteContactLast, routeStatus: 'ok', skippedResults } });
}

// Attach skippedResults to every valid row so it travels through the loop
return validRows.map(row => ({ json: { ...row.json, skippedResults } }));

const response = $input.item.json;
const rowData = $('Prep Contact Request').item.json;

let contactStatus, contactError;
if (response && response.error) {
  contactStatus = 'error';
  contactError = String(response.error);
} else if (response && response.errorCode === 0) {
  contactStatus = 'success';
} else {
  contactStatus = 'error';
  contactError = 'Unexpected response: ' + JSON.stringify(response);
}

return { json: { ...rowData, contactStatus, contactError } };

// Collect All Outcomes already computed status/detail/contact correctly.
// Just use it directly instead of re-deriving from fields that no longer exist here.
const allItems = $input.all();

const skippedResults = allItems.find(i => i.json.skippedResults)?.json.skippedResults || [];

const loopResults = allItems.map(item => {
  const d = item.json;
  return {
    jobNumber: d.jobNumber,
    siteAddress: d.siteAddress,
    contact: d.contact || '',
    email: d.email || '',
    status: d.status,
    detail: d.detail
  };
});

const results = [...skippedResults, ...loopResults];

const counts = { created: 0, created_contact_failed: 0, skipped_duplicate: 0, skipped_check_failed: 0, create_failed: 0, invalid: 0, duplicate_in_file: 0 };
for (const r of results) {
  if (counts[r.status] !== undefined) counts[r.status]++;
}

// Only show genuine problems in the table — not normal skipped duplicates
const issues = results.filter(r => 
  r.status !== 'created' && r.status !== 'skipped_duplicate'
);

let html = '<h3>Site import results</h3><ul>';
html += `<li>✅ Created: ${counts.created}</li>`;
html += `<li>⚠️ Created, contact failed: ${counts.created_contact_failed}</li>`;
html += `<li>⏭️ Skipped (already exists): ${counts.skipped_duplicate}</li>`;
html += `<li>❌ Failed to create: ${counts.create_failed}</li>`;
html += `<li>🚫 Invalid rows in file: ${counts.invalid}</li>`;
html += `<li>🔁 Duplicate rows within file: ${counts.duplicate_in_file}</li>`;
html += '</ul>';

if (issues.length > 0) {
  html += '<h4>Needs attention</h4>';
  html += '<table border="1" cellpadding="4" cellspacing="0" style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:13px;">';
  html += '<tr style="background:#f0f0f0"><th style="padding:8px">Job Number</th><th style="padding:8px">Site Address</th><th style="padding:8px">Status</th><th style="padding:8px">Detail</th></tr>';
  for (const r of issues) {
    html += `<tr><td style="padding:6px">${r.jobNumber}</td><td style="padding:6px">${r.siteAddress}</td><td style="padding:6px">${r.status}</td><td style="padding:6px">${r.detail}</td></tr>`;
  }
  html += '</table>';
} else {
  html += '<p>✅ Everything imported cleanly — nothing needs attention.</p>';
}

return [{ json: { summaryHtml: html, counts, results } }];

const items = $input.all();
const customerName = $('Site List Uploaded').first().json['Customer Name'].trim();

// Filter out items that are errors (continueOnFail passes error objects through)
const validItems = items.filter(i => i.json && i.json.uuid && !i.json.error);

if (validItems.length === 0) {
  // Could be API error or genuinely not found
  const hasError = items.some(i => i.json && i.json.error);
  return [{
    json: {
      lookupStatus: 'not_found',
      lookupError: hasError
        ? `ServiceM8 API error during client lookup: ${items[0].json.error}`
        : `No client found in ServiceM8 matching the name "${customerName}". Check the spelling and try again.`,
      customerName,
    }
  }];
}

if (validItems.length > 1) {
  const names = validItems.map(i => i.json.name).join(', ');
  return [{
    json: {
      lookupStatus: 'ambiguous',
      lookupError: `Multiple clients found matching "${customerName}": ${names}. Use a more specific name.`,
      customerName,
    }
  }];
}

// Exactly one match
const client = validItems[0].json;
return [{
  json: {
    lookupStatus: 'found',
    parentClientUUID: client.uuid,
    parentClientName: client.name,
    customerName,
  }
}];

const config = $('Config').first().json;
const client = $('Validate Client Lookup').first().json;
return [{
  json: {
    ...config,
    parentClientUUID: client.parentClientUUID,
    parentClientName: client.parentClientName,
  }
}];

// Merge Config And Client strips the binary.
// Pull it back from the Form Trigger item so Parse Spreadsheet can read it.
const formItem = $('Site List Uploaded').first();
const configItem = $('Merge Config And Client').first();
return [{
  json: configItem.json,
  binary: formItem.binary,
}];

// Each branch's HTTP call is already filtered to this row's PO number + client UUID,
// so $input.item is the single matching job (or this branch got 0 results).
const response = $input.item.json;
const rowData = $('Attach Job Context').item.json;

if (response && response.uuid) {
  return { json: { ...rowData, newJobUuid: response.uuid, createStatus: 'success', isAuthError: false } };
} else {
  return { json: { ...rowData, newJobUuid: null, createStatus: 'error', createError: 'Job created but UUID not found in ServiceM8', isAuthError: false } };
}

const allItems = $input.all();

// Separate by whether they have uuid (existing jobs) or jobNumber (spreadsheet rows)
const existingJobs = allItems.filter(i => i.json.uuid);
const spreadsheetRows = allItems.filter(i => i.json.jobNumber);

const parentUUID = $('Merge Config And Client').first().json.parentClientUUID;

// Build Set of existing PO numbers
const existingPOs = new Set(
  existingJobs
    .filter(j => j.json.company_uuid === parentUUID)
    .map(j => (j.json.purchase_order_number || '').toString().trim().toLowerCase())
);

// Return one item per spreadsheet row with alreadyExists correctly set
return spreadsheetRows.map(row => {
  const jobNumber = (row.json.jobNumber || '').toString().trim().toLowerCase();
  const alreadyExists = existingPOs.has(jobNumber);
  return {
    json: {
      ...row.json,
      parentClientUUID: parentUUID,
      alreadyExists
    }
  };
});

const item = $input.item.json;
return { json: {
  jobNumber: item.jobNumber,
  siteAddress: item.siteAddress,
  siteContactFirst: item.siteContactFirst || '',
  siteContactLast: item.siteContactLast || '',
  email: item.email,
  skippedResults: item.skippedResults || [],
  _result: 'skipped_duplicate',
  _detail: 'A job with this PO number already exists for this client - skipped'
}};

// Collect results from all branches.
// Each branch tags its item with _result and _detail.
const item = $input.item.json;

let status, detail;
if (item._result) {
  status = item._result;
  detail = item._detail;
} else if (item.createStatus === 'error') {
  status = 'create_failed';
  detail = item.createError || 'Job creation failed';
} else if (item.contactStatus === 'error') {
  status = 'created_contact_failed';
  detail = `Job ${item.newJobUuid} created, but contact failed: ${item.contactError}`;
} else {
  status = 'created';
  detail = `Job ${item.newJobUuid} created with PO ${item.jobNumber}`;
}

return { json: {
  jobNumber: item.jobNumber,
  siteAddress: item.siteAddress,
  contact: `${item.siteContactFirst||''} ${item.siteContactLast||''}`.trim(),
  email: item.email,
  skippedResults: item.skippedResults || [],
  status,
  detail
}};

// Create Job Card replaces the item with the raw API response, losing row context.
// Re-attach jobNumber/parentClientUUID/contact fields from Check And Route Each Row.
const response = $input.item.json;
const rowData = $('Check And Route Each Row').item.json;
return { json: { ...rowData, createResponse: response } };

// Carry row data forward explicitly before the HTTP node strips it
const item = $input.item.json;
return { json: item };
